using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = "gpt-4o-mini-2024-07-18";

// Build the chat client through MEAI abstractions
IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey)
    .AsIChatClient();

// Create the tools the agent can use
var tools = new AITool[]
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// Configure and create the agent
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using multiple queries.
        2. Save important findings as notes using the note-taking tool.
        3. After gathering enough information, retrieve all your notes and produce
           a well-structured summary with key findings and sources.
        Be thorough — perform at least 2-3 searches from different angles before summarizing.
        """,
    tools: tools);

// Prompt the user for a research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Run the agent
var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    }));

Console.WriteLine("── Research Summary ─────────────────────────────");
Console.WriteLine(response.Text);
Console.WriteLine("─────────────────────────────────────────────────");

return 0;

/// <summary>Tools available to the research agent.</summary>
static class ResearchTools
{
    private static readonly List<string> s_notes = [];
    private static readonly HttpClient s_http = new();

    [Description("Search the web for information on a query. Returns a summary of search results.")]
    public static async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var html = await s_http.SendAsync(request)
                .ContinueWith(t => t.Result.Content.ReadAsStringAsync())
                .Unwrap();

            // Extract text snippets from the HTML response
            var snippets = ExtractSnippets(html);
            if (snippets.Length == 0)
            {
                return $"No results found for '{query}'.";
            }

            return $"Search results for '{query}':\n{snippets}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important findings.")]
    public static string SaveNote(
        [Description("The note content to save")] string note)
    {
        s_notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({s_notes.Count} total)");
        return $"Note saved. You now have {s_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public static string GetNotes()
    {
        if (s_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        var result = string.Join("\n\n", s_notes.Select((n, i) => $"[Note {i + 1}] {n}"));
        Console.WriteLine($"  📋 Retrieved {s_notes.Count} note(s)");
        return result;
    }

    private static string ExtractSnippets(string html)
    {
        // Strip HTML tags and extract readable text snippets
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", " ");
        text = WebUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

        // Return a meaningful chunk (first ~2000 chars of extracted text)
        const int maxLength = 2000;
        return text.Length <= maxLength ? text : text[..maxLength] + "...";
    }
}

